script.text:
      /* <flatten type="Javascript"> */
function load$CheckingReport$(g) {
  g._$k = [];
  g._$i = g._getColumnOrder('xKey');
  g._$t = g._getColumnOrder('tag');
  g._$f = 'keys';
  g.add_commandEvent(on$GridReport$ExecuteCommand);
  g.add_onResponseComplete(on$GridReport$ResponseComplete);
}
function dispose$CheckingReport$(g) {
  g._$k = g._$i = g._$t = g._$f = null;
  try {g.remove_commandEvent(on$GridReport$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridReport$ResponseComplete);} catch (ex) {}
}
function scatter$GridReport$(g) {
  fill$Grid(g, true);
  if (g._rowCount > 0) {
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
  }
}
function on$GridReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, id = g.get_id(), s = String.format('$find(\'{0}\')._focusWhenTabChanged();', id);
  switch (action) {
    case 'Generate':
      var e = (g._language == 'v' ? 'Hệ thống sẽ <span class="Highlight">tạo dữ liệu kiểm kê cho các bản ghi mới</span>, bạn có chắc chắn thực hiện không?' : 'Are you sure you want to <span class="Highlight">generate data for new records</span>?');
      $message.show(e, 0, String.format('updateData(\'{0}\', "{1}");', id, action), s);
      break;
    case 'DeleteData':
      if (isCheck$Grid(g)) $message.show(g._getResources("Message.ConfirmDelete"), 0, String.format('deleteData(\'{0}\');', id), s);
      break;
    case 'DeleteAll':
      var e = (g._language == 'v' ? 'Hệ thống sẽ <span class="Highlight">xóa tất cả bản ghi</span>, bạn có chắc chắn xóa không?' : 'Are you sure you want to <span class="Highlight">delete all records</span>?');
      $message.show(e, 0, String.format('updateData(\'{0}\', "{1}");', id, action), s);
      break;
    default:
      break;
  }
}
function on$GridReport$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Generate':
    case 'DeleteData':
    case 'DeleteAll':
      if (result[0].Value == 1) {
        g.goToPage(-1);
        g._$k = [];
      }
      else {
        $message.show(result[0].Value, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
      }
      break;
    default:
      break;
  }
}
function updateData(id, c) {
  var g = $find(id);
  if (g._denyMessage) $message.show(g._denyMessage, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    else g.request(g, c, c, [['so_ct', 'String', g._so_ct]]);
}
function deleteData(id) {
  var g = $find(id);
  if (g._denyMessage) $message.show(g._denyMessage, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    else g.request(g, 'DeleteData', 'DeleteData', [['so_ct', 'String', g._so_ct], ['r', 'Infinite', ',' + $func.trim(g._$k.join()) + ',']]);
}
/* </flatten> */
      &JavascriptReportInit;
      &ScriptTagReport;
      &PrintRightScript;
